mapper.select:
SELECT ssc.id, ssc.student_id AS studentId, st.student_no AS studentNo, st.student_name AS studentName, ssc.type AS changeType, ssc.reason, ssc.start_date AS startDate, ssc.end_date AS endDate, ssc.tutor_approval AS mentorStatus, ssc.tutor_id AS mentorId, ssc.tutor_approval_time AS mentorApprovalTime, ssc.counselor_approval AS secretaryStatus, ssc.counselor_id AS secretaryId, ssc.counselor_approval_time AS secretaryApprovalTime, ssc.status, ssc.create_time AS createTime, ssc.update_time AS updateTime FROM student_status_change ssc LEFT JOIN student st ON ssc.student_id = st.id
AND ssc.student_id = #{studentId}
AND ssc.type = #{changeType}
AND st.student_no LIKE CONCAT('%', #{studentNo}, '%')
AND st.student_name LIKE CONCAT('%', #{studentName}, '%')
ORDER BY ssc.create_time DESC
